stylesheet:
QWidget {
    background: #141416;
    color: #d0d4dc;
    font-family: "JetBrains Sans", "Segoe UI Variable", "Segoe UI", "Arial", "Noto Sans", sans-serif;
    font-size: 10pt;
}
#WindowShell {
    background: transparent;
}
QStackedWidget, QStackedWidget > QWidget, QWidget#PagesShell, QStackedWidget#PagesStack {
    background: transparent;
}
QWidget[class="pageRoot"], QWidget[class="pageCanvas"] {
    background: transparent;
}
QLabel {
    background: transparent;
}
#RootFrame {
    background: #18181c;
    border: 1px solid #18181c;
    border-radius: 16px;
}
#TitleBar {
    background: #18181c;
    border: none;
    border-top-left-radius: 16px;
    border-top-right-radius: 16px;
}
#Sidebar {
    background: #18181c;
    border-bottom-left-radius: 16px;
}
#Content {
    background: transparent;
    border: none;
}
#ContentSurface {
    background: #141416;
    border-top: 1px solid #18181c;
    border-left: 1px solid #18181c;
    border-top-left-radius: 18px;
    border-top-right-radius: 0px;
    border-bottom-left-radius: 0px;
    border-bottom-right-radius: 16px;
}
QDialog#AppDialogWindow {
    background: transparent;
    border: none;
}
#DialogRoot {
    background: #1a1a20;
    border: 1px solid #303038;
    border-radius: 12px;
}
#DialogTitleBar {
    background: transparent;
    border: none;
    border-top-left-radius: 12px;
    border-top-right-radius: 12px;
}
#DialogBody {
    background: transparent;
}
#SettingsScroll, #SettingsCanvas, #SettingsScroll QWidget#qt_scrollarea_viewport {
    background: transparent;
    border: none;
}
QFrame[class="settingsSection"] {
    background: #1a1a20;
    border: 1px solid #303038;
    border-radius: 14px;
}
#LoadingOverlay {
    background: rgba(9, 13, 22, 0.42);
}
#LoadingCard {
    background: #1a1a20;
    border: 1px solid #404048;
    border-radius: 16px;
}
QFrame[class="card"] {
    background: #18181c;
    border: 1px solid #303038;
    border-radius: 16px;
}
QFrame[class="modHero"] {
    background: #1c1c22;
    border: 1px solid #18181c;
    border-radius: 16px;
}
QFrame[class="modCard"] {
    background: #1a1a20;
    border: 1px solid #303038;
    border-radius: 16px;
}
QFrame#NotificationsPopup {
    background: #1a1a20;
    border: 1px solid #353540;
    border-radius: 14px;
}
QFrame[class="notificationCard"] {
    background: #202026;
    border: 1px solid #353540;
    border-radius: 12px;
}
QScrollArea#NotificationsScroll, QWidget#NotificationsCanvas {
    background: transparent;
    border: none;
}
QFrame[class="modIconWrap"] {
    background: #22222a;
    border: 1px solid #404048;
    border-radius: 16px;
}
QLabel[class="title"] {
    font-size: 13pt;
    font-weight: 700;
    color: #eceef4;
}
#DashboardTitle {
    padding: 0px;
    margin: 0px;
}
#DashboardPowerBlock {
    background: transparent;
}
QLabel[class="muted"] {
    color: #90949c;
}
QLabel[class="modHint"] {
    color: #a0a4ac;
}
QLabel[class="modState"] {
    color: #eceef4;
    background: #22222a;
    border: 1px solid #404048;
    border-radius: 12px;
    padding: 6px 12px;
    font-weight: 600;
}
QLabel[class="modState"][state="enabled"] {
    background: rgba(44, 163, 93, 0.16);
    border: 1px solid #4d8b67;
    color: #a8efc1;
}
QLabel[class="modState"][state="installed"] {
    background: rgba(104, 137, 186, 0.16);
    border: 1px solid #606070;
    color: #c8c8e0;
}
QLabel[class="modState"][state="not installed"] {
    background: rgba(150, 164, 192, 0.12);
    border: 1px solid #505058;
    color: #a0a4ac;
}
QLabel[class="modMeta"] {
    color: #90949c;
    background: #1c1c22;
    border: 1px solid #303038;
    border-radius: 12px;
    padding: 6px 12px;
}
#ModsSummaryChip, #ModsEnabledChip {
    border-radius: 11px;
}
#ModStateBadge, #ModMetaChip {
    border-radius: 12px;
}
QLabel[class="modBody"] {
    color: #d0d4dc;
    line-height: 1.3em;
}
#ModsScroll, #ModsCanvas, #ComponentsScroll, #ComponentsCanvas {
    background: transparent;
    border: none;
}
#ComponentsScroll QScrollBar, #ComponentsCanvas QScrollBar, #ComponentsScroll QWidget#qt_scrollarea_viewport, #ComponentsCanvas QWidget#qt_scrollarea_viewport {
    background: transparent;
    border: none;
}
QToolButton[class="nav"] {
    min-width: 46px;
    min-height: 46px;
    max-width: 46px;
    max-height: 46px;
    border-radius: 12px;
    border: 1px solid transparent;
    background: transparent;
}
QToolButton[class="nav"]:hover {
    background: rgba(255, 255, 255, 0.02);
    border: 1px solid #22222a;
}
QToolButton[class="nav"]:checked {
    background: rgba(255, 255, 255, 0.045);
    border: 1px solid #2a2a34;
}
QToolButton[class="window"] {
    min-width: 26px;
    min-height: 26px;
    max-width: 26px;
    max-height: 26px;
    border-radius: 12px;
    border: none;
    background: transparent;
    padding: 0px;
    margin: 0px;
}
QToolButton[class="window"][role="min"],
QToolButton[class="window"][role="close"] {
    padding: 0px 1px 2px 0px;
}
QToolButton[class="window"][role="close"] {
    padding: 0px 1px 1px 0px;
}
QToolButton[class="window"]:hover {
    background: transparent;
}
QToolButton[class="window"][role="close"]:hover {
    background: rgba(170, 84, 97, 0.62);
}
QPushButton {
    background: #22222a;
    border: 1px solid #404048;
    border-radius: 10px;
    padding: 8px 12px;
}
QPushButton:hover {
    background: #22222a;
}
QToolButton[class="action"] {
    min-width: 26px;
    min-height: 26px;
    max-width: 26px;
    max-height: 26px;
    border: none;
    border-radius: 12px;
    background: transparent;
    padding: 0;
    margin: 0;
}
QToolButton[class="action"]:hover {
    background: transparent;
}
QToolButton[class="action"]::menu-indicator {
    image: none;
    width: 0px;
    height: 0px;
}
QFrame[class="fileModeCard"] {
    background: #1c1c22;
    border: 1px solid #353540;
    border-radius: 14px;
}
QFrame[class="fileModeCard"][hovered="true"] {
    background: #22222a;
    border: 1px solid #2a2a34;
}
QPushButton[class="primary"] {
    background: #5e6e8c;
    border-color: #404048;
    color: #ffffff;
    font-weight: 700;
}
QPushButton[class="primary"]:hover {
    background: #5e6e8c;
}
QPushButton[class="danger"] {
    background: #1a1a20;
    border-color: #fb5e5e;
    color: #ffd9dd;
    font-weight: 700;
}
QPushButton[class="danger"]:hover {
    background: #1a1a20;
}
QToolButton[class="power"] {
    min-width: 132px;
    min-height: 132px;
    max-width: 132px;
    max-height: 132px;
    border-radius: 66px;
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #6e7e9c, stop:0.48 #5e6e8c, stop:1 #4e5e7c);
    border: 2px solid #8e9ebc;
    padding: 0px;
}
QToolButton[class="power"][state="off"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #353540, stop:0.55 #22222a, stop:1 #181820);
    border: 2px solid #404048;
}
QToolButton[class="power"]:hover {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #8e9ebc, stop:0.48 #6e7e9c, stop:1 #7e8eac);
}
QToolButton[class="power"][state="off"]:hover {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #353540, stop:0.55 #505058, stop:1 #353540);
}
#LogsFilesShell {
    background: #18181c;
    border: 1px solid #18181c;
    border-radius: 16px;
}
QTabWidget::pane {
    background: transparent;
    border: none;
}
QTabBar::tab {
    background: #141416;
    border: 1px solid #353540;
    border-radius: 8px;
    padding: 6px 16px;
    margin-right: 4px;
    color: #a0a4ac;
}
QTabBar::tab:selected {
    background: #5e6e8c;
    border-color: #7e8eac;
    color: #ffffff;
}
QTabBar::tab:hover:!selected {
    background: #22222a;
}
QPushButton[class="settingsSegment"] {
    background: #141416;
    border: 1px solid #353540;
    border-radius: 8px;
    color: #a0a4ac;
    font-size: 9pt;
    padding: 4px 12px;
    margin: 0px;
}
QPushButton[class="settingsSegment"]:hover {
    background: #22222a;
}
QPushButton[class="settingsSegment"]:checked {
    background: #5e6e8c;
    color: #ffffff;
    border-color: #7e8eac;
}
QLineEdit, QComboBox, QTextEdit, QTableWidget {
    background: #141416;
    border: 1px solid #353540;
    border-radius: 10px;
    padding: 6px;
    selection-background-color: #404048;
}
QCheckBox {
    background: transparent;
    spacing: 8px;
    padding: 2px 0;
}
QCheckBox::indicator {
    width: 16px;
    height: 16px;
    border-radius: 5px;
    border: 1px solid #606070;
    background: transparent;
}
QCheckBox::indicator:unchecked:hover {
    background: rgba(83, 108, 148, 0.18);
}
QCheckBox::indicator:checked {
    border: 1px solid #8e9ebc;
    background: #5e6e8c;
    __CHECK_ICON__
}
QComboBox::drop-down {
    subcontrol-origin: padding;
    subcontrol-position: top right;
    width: 22px;
    border: none;
    background: transparent;
}
QComboBox::down-arrow {
    width: 12px;
    height: 12px;
    __COMBO_ARROW__
}
QListWidget {
    background: #141416;
    border: 1px solid #353540;
    border-radius: 12px;
    padding: 8px;
    outline: none;
}
QListWidget::item {
    background: #202026;
    border: 1px solid #353540;
    border-radius: 10px;
    padding: 10px;
    margin: 2px 0;
}
QListWidget::item:selected {
    background: #2a2a34;
    border: 1px solid #5e6e8c;
}
QListWidget::item:hover {
    background: #2a2a34;
}
QHeaderView::section {
    background: #22222a;
    color: #d0d4dc;
    border: none;
    padding: 6px;
}
QScrollBar:vertical {
    background: transparent;
    border: none;
    width: 0px;
    margin: 0px;
}
QScrollBar::groove:vertical {
    background: transparent;
    border: none;
    margin: 0px;
}
QScrollBar::handle:vertical {
    background: transparent;
    min-height: 34px;
    border-radius: 4px;
}
QScrollBar::handle:vertical:hover {
    background: transparent;
}
QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {
    height: 0px;
}
QScrollBar::add-page:vertical, QScrollBar::sub-page:vertical {
    background: transparent;
}
QScrollBar:horizontal {
    background: transparent;
    border: none;
    height: 0px;
    margin: 0px;
}
QScrollBar::groove:horizontal {
    background: transparent;
    border: none;
    margin: 0px;
}
QScrollBar::handle:horizontal {
    background: transparent;
    min-width: 34px;
    border-radius: 4px;
}
QScrollBar::handle:horizontal:hover {
    background: transparent;
}
QScrollBar::add-line:horizontal, QScrollBar::sub-line:horizontal {
    width: 0px;
}
QScrollBar::add-page:horizontal, QScrollBar::sub-page:horizontal {
    background: transparent;
}
QListWidget#FilesList, QListWidget#FilesList::viewport,
QListWidget#ModFilesList, QListWidget#ModFilesList::viewport {
    background: transparent;
    border: none;
}
QListWidget#FilesList {
    padding: 0px;
}
QListWidget#ModFilesList {
    padding: 4px;
    border: 1px solid #404048;
    border-radius: 12px;
}
QListWidget#FilesList::item,
QListWidget#ModFilesList::item {
    margin: 0px 0px 8px 0px;
}
QListWidget#FilesList::item:selected,
QListWidget#ModFilesList::item:selected {
    color: #d0d4dc;
}
QListWidget#FilesList QScrollBar:vertical,
QListWidget#ModFilesList QScrollBar:vertical,
QTextEdit#FileEditor QScrollBar:vertical {
    background: transparent;
    border: none;
    width: 0px;
    margin: 0px;
}
QListWidget#FilesList QScrollBar::handle:vertical,
QListWidget#ModFilesList QScrollBar::handle:vertical,
QTextEdit#FileEditor QScrollBar::handle:vertical {
    background: transparent;
    min-height: 40px;
    border-radius: 4px;
}
QListWidget#FilesList QScrollBar:horizontal,
QListWidget#ModFilesList QScrollBar:horizontal,
QTextEdit#FileEditor QScrollBar:horizontal {
    background: transparent;
    border: none;
    height: 0px;
    margin: 0px;
}
QListWidget#FilesList QScrollBar::handle:horizontal,
QListWidget#ModFilesList QScrollBar::handle:horizontal,
QTextEdit#FileEditor QScrollBar::handle:horizontal {
    background: transparent;
    min-width: 40px;
    border-radius: 4px;
}
QListWidget#FilesList QScrollBar::add-page:vertical,
QListWidget#FilesList QScrollBar::sub-page:vertical,
QListWidget#ModFilesList QScrollBar::add-page:vertical,
QListWidget#ModFilesList QScrollBar::sub-page:vertical,
QTextEdit#FileEditor QScrollBar::add-page:vertical,
QTextEdit#FileEditor QScrollBar::sub-page:vertical,
QListWidget#FilesList QScrollBar::add-page:horizontal,
QListWidget#FilesList QScrollBar::sub-page:horizontal,
QListWidget#ModFilesList QScrollBar::add-page:horizontal,
QListWidget#ModFilesList QScrollBar::sub-page:horizontal,
QTextEdit#FileEditor QScrollBar::add-page:horizontal,
QTextEdit#FileEditor QScrollBar::sub-page:horizontal {
    background: transparent;
}
QListWidget#FilesList QScrollBar::groove:vertical,
QListWidget#FilesList QScrollBar::groove:horizontal,
QListWidget#ModFilesList QScrollBar::groove:vertical,
QListWidget#ModFilesList QScrollBar::groove:horizontal,
QTextEdit#FileEditor QScrollBar::groove:vertical,
QTextEdit#FileEditor QScrollBar::groove:horizontal,
QAbstractScrollArea::corner {
    background: transparent;
    border: none;
}
QMenu {
    background: #1a1a20;
    border: 1px solid #353540;
    border-radius: 8px;
    padding: 6px;
}
QMenu::item {
    padding: 7px 10px;
    border-radius: 6px;
}
QMenu::item:selected {
    background: #2a2a34;
}
